{
  "name": "write_file",
  "arguments": {
    "path": "static/style.css",
    "content": "/* static/style.css */

body {
  font-family: Arial, sans-serif;
  margin: 0;
  padding: 0;
  background-color: #f4f4f9;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}

.news-card {
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  background-color: #fff;
  margin-bottom: 20px;
}

.news-card img {
  width: 100%;
  border-top-left-radius: 8px;
  border-top-right-radius: 8px;
}

.news-card h2 {
  font-size: 24px;
  margin: 15px 0;
  padding: 0;
}

.news-card p {
  font-size: 16px;
  line-height: 1.5;
  color: #6c757d;
  margin: 10px 0;
}

.news-card .meta {
  font-size: 14px;
  color: #9e9e9e;
  margin-top: 10px;
}

a {
  text-decoration: none;
  color: #007bff;
}

a:hover {
  text-decoration: underline;
}"
  }
}
